 1→import { createContext, useContext } from 'react';
 2→
 3→interface ListContextValue {
 4→  activeIndex: number;
 5→  setActiveIndex: (index: number) => void;
 6→}
 7→
 8→export const ListContext = createContext<ListContextValue | null>(null);
 9→
10→export function useListContext(): ListContextValue {
11→  const context = useContext(ListContext);
12→  if (!context) {
13→    throw new Error('useListContext must be used within a List');
14→  }
15→  return context;
16→}
